import type Quill from "quill";
import type { Range } from "quill";
import type { Options, ImageResizeOptions, Modules } from "./types";
import { DisplaySize } from "./modules/DisplaySize";
import { Resize } from "./modules/Resize";
import { AltText } from "./modules/AltText";
/**
 * Custom module for quilljs to allow user to resize <img> elements
 * (Works on Chrome, Edge, Safari and replaces Firefox's native resize behavior)
 * @see https://quilljs.com/blog/building-a-custom-module/
 */
export default class ImageResize {
    quill: Quill;
    options: Options;
    moduleClasses: Modules;
    modules: (DisplaySize | Resize | AltText)[];
    img: HTMLImageElement | null;
    overlay: HTMLDivElement | null;
    constructor(quill: Quill, options?: ImageResizeOptions);
    initializeModules: () => void;
    onUpdate: () => void;
    removeModules: () => void;
    handleClick: (event: MouseEvent) => void;
    handleSelectionChange: (range: Range | null) => void;
    handleTextChange: () => void;
    show: (img: HTMLImageElement) => void;
    showOverlay: () => void;
    hideOverlay: () => void;
    repositionElements: () => void;
    hide: () => void;
    setUserSelect: (value: string) => void;
    handleKeyboardShortcuts: (event: KeyboardEvent) => void;
}
